 56→export function HomeFeedScreen({navigation}: Props) {
 57→  const {user, session} = useAuth();
 58→  const {colors} = useTheme();
 59→  const token = session?.access_token ?? '';
 60→  const [refreshing, setRefreshing] = useState(false);
 61→  const [activeFilter, setActiveFilter] = useState('all');
 62→  const [commentModal, setCommentModal] = useState<{postId: string; receiverId?: string; commentCount: number} | null>(null);
 63→  const [repostModal, setRepostModal] = useState<{journalId: string; title?: string; authorName?: string; authorAvatar?: string} | null>(null);
 64→
 65→  const feedQuery = useInfiniteQuery({
 66→    queryKey: ['feed', user?.id],
 67→    queryFn: ({pageParam}) =>
 68→      mobileApi.getJournals(pageParam ?? null, PAGE_SIZE, user?.id),
 69→    initialPageParam: null as string | null,
 70→    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
 71→  });
 72→
 73→  const reactionMutation = useMutation({
 74→    mutationFn: async ({
 75→      journalId,
 76→      receiverId,
 77→      reactionType,
 78→    }: {
 79→      journalId: string;
 80→      receiverId: string;
 81→      reactionType: string;
 82→    }) => {
 83→      if (!token) throw new Error('Please log in to react.');
 84→      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
 85→    },
 86→    onMutate: async ({journalId, reactionType}) => {
 87→      await queryClient.cancelQueries({queryKey: ['feed']});
 88→      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(
 89→        ['feed', user?.id],
 90→      );
 91→      if (prev) {
 92→        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(
 93→          ['feed', user?.id],
 94→          old => {
 95→            if (!old) return old;
 96→            return {
 97→              ...old,
 98→              pages: old.pages.map(page => ({
 99→                ...page,
100→                data: page.data.map(item => {
101→                  if (item.id !== journalId) return item;
102→                  const removing = item.user_reaction === reactionType;
103→                  const currentCount =
104→                    (item.reaction_count?.[0]?.count ??
105→                      item.like_count?.[0]?.count ??
106→                      item.likes_count ??
107→                      0) as number;
108→                  const delta = removing ? -1 : item.user_reaction ? 0 : 1;
109→                  return {
110→                    ...item,
111→                    user_reaction: removing ? null : reactionType,
112→                    has_liked: removing ? false : true,
113→                    like_count: [{count: Math.max(0, currentCount + delta)}],
114→                  };
115→                }),
116→              })),
117→            };
118→          },
119→        );
120→      }
121→      return {prev};
122→    },
123→    onError: (_err, _vars, context) => {
124→      if (context?.prev) {
125→        queryClient.setQueryData(['feed', user?.id], context.prev);
126→      }
127→    },
128→    onSettled: () => {
129→      queryClient.invalidateQueries({queryKey: ['feed']});
130→    },
131→  });
132→
133→  const bookmarkMutation = useBookmarkMutation(token, ['feed', user?.id]);
134→
135→  const handleReact = (journalId: string, receiverId: string, reactionType: string) => {
136→    if (!token) return;
137→    reactionMutation.mutate({journalId, receiverId, reactionType});
138→  };
139→
140→  const handleComment = (journalId: string, receiverId?: string, commentCount?: number) => {
141→    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
142→  };
143→
144→  const handleBookmark = (journalId: string) => {
145→    bookmarkMutation.mutate(journalId);
146→  };
147→
148→  const handleRepost = (journalId: string, title?: string, authorName?: string, authorAvatar?: string) => {
149→    setRepostModal({journalId, title, authorName, authorAvatar});
150→  };

