import React, {useMemo} from 'react';
import {Image, StyleSheet, Text, View} from 'react-native';
import Svg, {Polyline} from 'react-native-svg';
import {fonts} from '../../theme/typography';
import {parseCanvasDoc} from '../../lib/utils/journalHelpers';
import type {CanvasDoc, CanvasDoodle, CanvasImage, CanvasSnippet} from '../../lib/api/mobileApi';

interface CanvasPreviewProps {
  canvasDoc: CanvasDoc | string | null;
  width: number;
}

const STAGE_WIDTH = 560;

const ASPECT_RATIOS: Record<string, number> = {
  '1:1': 1,
  '4:5': 4 / 5,
};

const FONT_MAP: Record<string, string> = {
  handwritten: fonts.brand.semiBoldItalic,
  serif: fonts.serif.regular,
  mono: fonts.serif.regular,
  bold: fonts.ui.bold,
  serifDisplay: fonts.brand.semiBold,
};

const BASE_FONT_SIZES: Record<string, number> = {
  bold: 34,
  handwritten: 32,
};
const DEFAULT_BASE_SIZE = 30;
const MIN_FONT = 6;
const MAX_FONT = 48;

function clamp(value: number, min: number, max: number) {
  return Math.min(max, Math.max(min, value));
}

export function CanvasPreview({canvasDoc, width}: CanvasPreviewProps) {
  const doc = useMemo(() => parseCanvasDoc(canvasDoc), [canvasDoc]);

  const hasContent =
    (doc?.snippets?.length ?? 0) > 0 ||
    (doc?.images?.length ?? 0) > 0 ||
    (doc?.doodles?.length ?? 0) > 0;

  if (!doc || !hasContent) return null;

  const ratio = ASPECT_RATIOS[doc.meta?.aspectRatio ?? ''] ?? 4 / 5;
  const height = Math.min(180, width / ratio);
  const scale = width / STAGE_WIDTH;
  const bgColor = doc.meta?.theme === 'dark' ? '#1A1A1A' : '#FAFAFA';
  const defaultTextColor = doc.meta?.theme === 'dark' ? '#FAFAFA' : '#1A1A1A';

  const sortedImages = [...(doc.images ?? [])].sort(
    (a, b) => (a.zIndex ?? 0) - (b.zIndex ?? 0),
  );
  const sortedSnippets = [...(doc.snippets ?? [])].sort(
    (a, b) => (a.zIndex ?? 0) - (b.zIndex ?? 0),
  );

  return (
    <View style={[styles.container, {width, height, backgroundColor: bgColor}]}>
      {/* Images layer */}
      {sortedImages.map((img: CanvasImage) => (
        <Image
          key={img.id}
          source={{uri: img.src}}
          style={{
            position: 'absolute',
            left: img.x * width,
            top: img.y * height,
            width: img.width * width,
            height: img.height * height,
            transform: [
              ...(img.rotation ? [{rotate: `${img.rotation}deg`}] : []),
              ...(img.scaleX != null && img.scaleX < 0 ? [{scaleX: -1}] : []),
            ],
          }}
          resizeMode="cover"
        />
      ))}

      {/* Text snippets layer */}
      {sortedSnippets.map((snippet: CanvasSnippet) => {
        const baseSize = BASE_FONT_SIZES[snippet.fontStyle ?? ''] ?? DEFAULT_BASE_SIZE;
        const sizeScale = snippet.sizeScale ?? 1;
        const fontSize = clamp(baseSize * sizeScale * scale, MIN_FONT, MAX_FONT);
        const fontFamily = FONT_MAP[snippet.fontStyle ?? ''] ?? fonts.ui.regular;

        return (
          <Text
            key={snippet.id}
            numberOfLines={3}
            style={{
              position: 'absolute',
              left: snippet.x * width,
              top: snippet.y * height,
              fontSize,
              fontFamily,
              color: defaultTextColor,
              transform: [
                ...(snippet.rotation ? [{rotate: `${snippet.rotation}deg`}] : []),
                ...(snippet.scaleX != null && snippet.scaleX < 0 ? [{scaleX: -1}] : []),
              ],
            }}>
            {snippet.text}
          </Text>
        );
      })}

      {/* Doodles layer */}
      {doc.doodles && doc.doodles.length > 0 ? (
        <Svg
          width={width}
          height={height}
          style={StyleSheet.absoluteFill}
          pointerEvents="none">
          {doc.doodles.map((doodle: CanvasDoodle) => {
            const pts = doodle.points;
            if (!pts || pts.length < 4) return null;
            const pointStr = [];
            for (let i = 0; i < pts.length; i += 2) {
              pointStr.push(`${pts[i] * width},${pts[i + 1] * height}`);
            }
            return (
              <Polyline
                key={doodle.id}
                points={pointStr.join(' ')}
                fill="none"
                stroke={doodle.color ?? defaultTextColor}
                strokeWidth={Math.max(1, (doodle.size ?? 2) * scale)}
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            );
          })}
        </Svg>
      ) : null}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    overflow: 'hidden',
  },
});

