import React, {useMemo, useState} from 'react';
import {FlatList, ScrollView, StyleSheet, Text, View, useWindowDimensions} from 'react-native';
import {useInfiniteQuery, useMutation} from '@tanstack/react-query';
import {NativeStackScreenProps} from '@react-navigation/native-stack';
import {SafeAreaView} from 'react-native-safe-area-context';
import {PostCard} from '../../components/PostCard/PostCard';
import {CanvasPreview} from '../../components/CanvasPreview/CanvasPreview';
import {PostCardSkeleton} from '../../components/SkeletonLoader';
import {CommentModal} from '../../components/Comments';
import {RepostModal} from '../../components/RepostModal';
import {Chip} from '../../components/Chip';
import {EmptyState} from '../../components/EmptyState';
import {useAuth} from '../../features/auth/AuthProvider';
import {useTheme} from '../../theme/ThemeProvider';
import {fonts} from '../../theme/typography';
import {spacing} from '../../theme/spacing';
import {
  mobileApi,
  type CursorPage,
  type JournalItem,
} from '../../lib/api/mobileApi';
import {socialApi} from '../../lib/api/socialApi';
import {queryClient} from '../../lib/queryClient';
import {useBookmarkMutation} from '../../hooks/useSocialMutations';
import {
  extractPlainText,
  resolveCount,
  getNextCursor,
  getCanvasPlainText,
} from '../../lib/utils/journalHelpers';
import type {RootStackParamList} from '../../navigation/types';

type Props = NativeStackScreenProps<RootStackParamList, 'Canvas'>;

const PAGE_SIZE = 10;

const SORT_OPTIONS = [
  {key: 'hottest', label: 'Hottest'},
  {key: 'newest', label: 'Newest'},
] as const;

type SortKey = (typeof SORT_OPTIONS)[number]['key'];

export function CanvasScreen({navigation}: Props) {
  const {user, session} = useAuth();
  const {colors} = useTheme();
  const {width: windowWidth} = useWindowDimensions();
  const cardWidth = windowWidth - spacing.lg * 2;
  const token = session?.access_token ?? '';
  const [refreshing, setRefreshing] = useState(false);
  const [sort, setSort] = useState<SortKey>('hottest');
  const [commentModal, setCommentModal] = useState<{
    postId: string;
    receiverId?: string;
    commentCount: number;
  } | null>(null);
  const [repostModal, setRepostModal] = useState<{
    journalId: string;
    title?: string;
    authorName?: string;
    authorAvatar?: string;
  } | null>(null);

  const galleryQuery = useInfiniteQuery({
    queryKey: ['canvas-gallery', user?.id, sort],
    queryFn: ({pageParam}) =>
      mobileApi.getCanvasGallery(user?.id, PAGE_SIZE, sort, pageParam ?? null),
    initialPageParam: null as string | null,
    getNextPageParam: lastPage => getNextCursor(lastPage, PAGE_SIZE),
  });

  const reactionMutation = useMutation({
    mutationFn: async ({
      journalId,
      receiverId,
      reactionType,
    }: {
      journalId: string;
      receiverId: string;
      reactionType: string;
    }) => {
      if (!token) throw new Error('Please log in to react.');
      return socialApi.toggleReaction(token, {journalId, receiverId, reactionType});
    },
    onMutate: async ({journalId, reactionType}) => {
      const qk = ['canvas-gallery', user?.id, sort];
      await queryClient.cancelQueries({queryKey: qk});
      const prev = queryClient.getQueryData<{pages: CursorPage<JournalItem>[]}>(qk);
      if (prev) {
        queryClient.setQueryData<{pages: CursorPage<JournalItem>[]}>(qk, old => {
          if (!old) return old;
          return {
            ...old,
            pages: old.pages.map(page => ({
              ...page,
              data: page.data.map(item => {
                if (item.id !== journalId) return item;
                const removing = item.user_reaction === reactionType;
                const currentCount =
                  (item.reaction_count?.[0]?.count ??
                    item.like_count?.[0]?.count ??
                    item.likes_count ??
                    0) as number;
                const delta = removing ? -1 : item.user_reaction ? 0 : 1;
                return {
                  ...item,
                  user_reaction: removing ? null : reactionType,
                  has_liked: removing ? false : true,
                  like_count: [{count: Math.max(0, currentCount + delta)}],
                };
              }),
            })),
          };
        });
      }
      return {prev};
    },
    onError: (_err, _vars, context) => {
      if (context?.prev) {
        queryClient.setQueryData(
          ['canvas-gallery', user?.id, sort],
          context.prev,
        );
      }
    },
    onSettled: () => {
      queryClient.invalidateQueries({queryKey: ['canvas-gallery']});
    },
  });

  const bookmarkMutation = useBookmarkMutation(token, [
    'canvas-gallery',
    user?.id,
    sort,
  ]);

  const handleReact = (
    journalId: string,
    receiverId: string,
    reactionType: string,
  ) => {
    if (!token) return;
    reactionMutation.mutate({journalId, receiverId, reactionType});
  };

  const handleComment = (
    journalId: string,
    receiverId?: string,
    commentCount?: number,
  ) => {
    setCommentModal({postId: journalId, receiverId, commentCount: commentCount ?? 0});
  };

  const handleBookmark = (journalId: string) => {
    bookmarkMutation.mutate(journalId);
  };

  const handleRepost = (
    journalId: string,
    title?: string,
    authorName?: string,
    authorAvatar?: string,
  ) => {
    setRepostModal({journalId, title, authorName, authorAvatar});
  };

  const posts = useMemo(
    () => galleryQuery.data?.pages.flatMap(page => page.data ?? []) ?? [],
    [galleryQuery.data?.pages],
  );

  const onRefresh = async () => {
    setRefreshing(true);
    try {
      await galleryQuery.refetch();
    } finally {
      setRefreshing(false);
    }
  };

  return (
    <SafeAreaView
      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
      edges={['top']}>
      {/* Header */}
      <View style={[styles.header, {borderBottomColor: colors.borderCard}]}>
        <Text style={[styles.brandText, {color: colors.textHeading}]}>
          Canvas
        </Text>
      </View>

      {/* Sort chips */}
      <View style={styles.chipRow}>
        <ScrollView
          horizontal
          showsHorizontalScrollIndicator={false}
          contentContainerStyle={styles.chipScroll}>
          {SORT_OPTIONS.map(option => (
            <Chip
              key={option.key}
              label={option.label}
              active={sort === option.key}
              onPress={() => setSort(option.key)}
            />
          ))}
        </ScrollView>
      </View>

      {/* Gallery */}
      <FlatList
        data={posts}
        onRefresh={onRefresh}
        refreshing={refreshing}
        onEndReachedThreshold={0.25}
        onEndReached={() => {
          if (galleryQuery.hasNextPage && !galleryQuery.isFetchingNextPage) {
            galleryQuery.fetchNextPage();
          }
        }}
        contentContainerStyle={styles.listContent}
        showsVerticalScrollIndicator={false}
        ListEmptyComponent={
          galleryQuery.isLoading ? (
            <View style={styles.skeletonList}>
              <PostCardSkeleton />
              <PostCardSkeleton />
              <PostCardSkeleton />
            </View>
          ) : (
            <EmptyState
              title="No canvas posts yet"
              subtitle="Pull to refresh or create your first canvas post."
            />
          )
        }
        ListFooterComponent={
          galleryQuery.isFetchingNextPage ? (
            <View style={styles.loadingMore}>
              <PostCardSkeleton />
            </View>
          ) : null
        }
        keyExtractor={item => item.id}
        renderItem={({item}) => {
          const canvasText = getCanvasPlainText(item.canvas_doc);
          const preview = (canvasText || extractPlainText(item.content)).slice(0, 180);
          const likeCount = resolveCount(item.like_count, item.likes_count);
          const commentCount = resolveCount(
            item.comment_count,
            item.comments_count,
          );
          const bookmarkCount = resolveCount(item.bookmark_count);
          const bannerNode = (
            <CanvasPreview canvasDoc={item.canvas_doc ?? null} width={cardWidth} />
          );

          const receiverId = item.user_id ?? item.users?.id ?? '';

          const handleAuthorPress = () => {
            const authorId = item.users?.id ?? item.user_id;
            if (!authorId) return;
            if (authorId === user?.id) {
              navigation.navigate('Main' as any, {screen: 'Profile'});
            } else {
              navigation.navigate('VisitProfile', {
                userId: authorId,
                username: item.users?.username ?? undefined,
              });
            }
          };

          const isRepost = !!item.is_repost;
          const repostSource = isRepost ? item.repost_source : null;
          const repostSourcePreview = repostSource?.content
            ? extractPlainText(repostSource.content).slice(0, 180)
            : '';

          return (
            <PostCard
              title={item.title || 'Untitled Post'}
              bodyPreview={preview || 'No preview text available.'}
              authorName={item.users?.name || 'Unknown author'}
              authorAvatar={item.users?.image_url}
              authorBadge={item.users?.badge as 'legend' | 'og' | undefined}
              bannerContent={bannerNode}
              postType={item.post_type ?? 'canvas'}
              likeCount={likeCount}
              commentCount={commentCount}
              bookmarkCount={bookmarkCount}
              userReaction={item.user_reaction}
              isBookmarked={!!item.has_bookmarked}
              onReact={type => handleReact(item.id, receiverId, type)}
              onComment={() => handleComment(item.id, receiverId, commentCount)}
              onBookmark={() => handleBookmark(item.id)}
              onRepost={() =>
                handleRepost(
                  item.id,
                  item.title ?? undefined,
                  item.users?.name ?? undefined,
                  item.users?.image_url ?? undefined,
                )
              }
              onPress={() =>
                navigation.navigate('PostDetail', {journalId: item.id})
              }
              onAuthorPress={handleAuthorPress}
              isRepost={isRepost}
              repostCaption={item.repost_caption}
              repostSourceTitle={repostSource?.title}
              repostSourcePreview={repostSourcePreview}
              repostSourceAuthorName={repostSource?.users?.name}
              repostSourceAuthorAvatar={repostSource?.users?.image_url}
              onEmbeddedPress={
                repostSource
                  ? () =>
                      navigation.navigate('PostDetail', {
                        journalId: repostSource.id,
                      })
                  : undefined
              }
            />
          );
        }}
        ItemSeparatorComponent={() => <View style={styles.separator} />}
      />

      {commentModal && (
        <CommentModal
          visible
          postId={commentModal.postId}
          receiverId={commentModal.receiverId}
          commentCount={commentModal.commentCount}
          onClose={() => setCommentModal(null)}
        />
      )}

      {repostModal && (
        <RepostModal
          visible
          sourceJournalId={repostModal.journalId}
          title={repostModal.title}
          authorName={repostModal.authorName}
          authorAvatar={repostModal.authorAvatar}
          onClose={() => setRepostModal(null)}
        />
      )}
    </SafeAreaView>
  );
}

const styles = StyleSheet.create({
  safe: {
    flex: 1,
  },
  header: {
    paddingHorizontal: spacing.lg,
    paddingVertical: spacing.md,
    borderBottomWidth: StyleSheet.hairlineWidth,
  },
  brandText: {
    fontFamily: fonts.brand.semiBold,
    fontSize: 24,
    letterSpacing: 1,
  },
  chipRow: {
    paddingVertical: spacing.sm,
  },
  chipScroll: {
    paddingHorizontal: spacing.lg,
    gap: spacing.sm,
  },
  listContent: {
    paddingHorizontal: spacing.lg,
    paddingBottom: 100,
  },
  separator: {
    height: spacing.md,
  },
  skeletonList: {
    gap: spacing.md,
    paddingTop: spacing.md,
  },
  loadingMore: {
    paddingTop: spacing.md,
  },
});

