174→  };
175→
176→  return (
177→    <SafeAreaView
178→      style={[styles.safe, {backgroundColor: colors.bgPrimary}]}
179→      edges={['top']}>
180→      {/* Branded header */}
181→      <View
182→        style={[
183→          styles.header,
184→          {borderBottomColor: colors.borderCard},
185→        ]}>
186→        <Text style={[styles.brandText, {color: colors.textHeading}]}>
187→          iskrib
188→        </Text>
189→      </View>
190→
191→      {/* Filter chips */}
192→      <View style={styles.chipRow}>
193→        <ScrollView
194→          horizontal
195→          showsHorizontalScrollIndicator={false}
196→          contentContainerStyle={styles.chipScroll}>
197→          {QUICK_ACTIONS.map(action => (
198→            <Chip
199→              key={action.key}
200→              label={action.label}
201→              active={activeFilter === action.key}
202→              onPress={() => handleQuickAction(action.key)}
203→            />
204→          ))}
205→        </ScrollView>
206→      </View>
207→
208→      {/* Feed */}
209→      <FlatList
210→        data={posts}
211→        onRefresh={onRefresh}
212→        refreshing={refreshing}
213→        onEndReachedThreshold={0.25}
214→        onEndReached={() => {
215→          if (feedQuery.hasNextPage && !feedQuery.isFetchingNextPage) {
216→            feedQuery.fetchNextPage();
217→          }
218→        }}
219→        contentContainerStyle={styles.listContent}
220→        showsVerticalScrollIndicator={false}
221→        ListEmptyComponent={
222→          feedQuery.isLoading ? (
223→            <View style={styles.skeletonList}>
224→              <PostCardSkeleton />
225→              <PostCardSkeleton />
226→              <PostCardSkeleton />
227→            </View>
228→          ) : (
229→            <EmptyState
230→              title="No posts yet"
231→              subtitle="Pull to refresh or create your first journal post."
232→            />
233→          )
234→        }
235→        ListFooterComponent={
236→          feedQuery.isFetchingNextPage ? (
237→            <View style={styles.loadingMore}>
238→              <PostCardSkeleton />
239→            </View>
240→          ) : null
241→        }
242→        keyExtractor={item => item.id}
243→        renderItem={({item}) => {
244→          const preview = extractPlainText(item.content).slice(0, 180);
245→          const likeCount = resolveCount(
246→            item.like_count,
247→            item.likes_count,
248→          );
249→          const commentCount = resolveCount(
250→            item.comment_count,
251→            item.comments_count,
252→          );
253→          const bookmarkCount = resolveCount(item.bookmark_count);
